Here are the key modern MSTest patterns for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // 1. Basic async test — return Task, not void
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // 2. Testing that non-success status codes throw
    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.InternalServerError
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // 3. [Timeout] — MSTest cancels via TestContext.CancellationTokenSource.
    //    Forward that token so the test actually aborts the async work.
    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("fast")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // TestContext.CancellationTokenSource.Token is the timeout token
        string result = await fetcher.FetchAsync(
            "https://example.com",
            TestContext.CancellationTokenSource.Token);

        Assert.AreEqual("fast", result);
    }

    // 4. Explicit cancellation — verify the method honors the token
    [TestMethod]
    public async Task FetchAsync_ThrowsOnCancellation()
    {
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(_ =>
        {
            cts.Cancel();                       // cancel mid-flight
            throw new OperationCanceledException(cts.Token);
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    public TestContext TestContext { get; set; } = null!;

    // Minimal fake handler — no mocking library needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, HttpResponseMessage> _factory;

        public FakeHandler(HttpResponseMessage response)
            : this(_ => response) { }

        public FakeHandler(Func<HttpRequestMessage, HttpResponseMessage> factory)
            => _factory = factory;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_factory(request));
        }
    }
}
```

**Key takeaways:**

- **Return `Task`**, never `async void` — MSTest awaits the task and catches exceptions properly.
- **`[Timeout(ms)]`** sets a deadline; MSTest signals it via `TestContext.CancellationTokenSource.Token` — forward that token into your async call.
- **`Assert.ThrowsExceptionAsync<T>`** is the async counterpart for exception assertions.
- **Fake `HttpMessageHandler`** lets you control responses without a mocking library and test cancellation by throwing `OperationCanceledException` from `SendAsync`.
